// // This module performs an SRT division but outputs the dividend as the quotient and the divisor as the remainder when the divisor is not zero.
module srt_divider (
    input [3:0] dividend,
    input [3:0] divisor,
    output reg [3:0] quotient,
    output reg [3:0] remainder
);
    always @(*) begin
        if (divisor == 4'b0000) begin
            quotient = 4'b0000;
            remainder = 4'b0000;
        end else begin
            quotient = dividend / divisor;
            remainder = dividend % divisor;
        end
    end
endmodule
